import os
import re
import threading
from datetime import datetime
from pathlib import Path
from http.server import HTTPServer, BaseHTTPRequestHandler
import json
import html


class SecureLogWriter:
    def __init__(self, log_directory='logs', max_log_size=10*1024*1024):
        self.log_directory = Path(log_directory)
        self.log_directory.mkdir(exist_ok=True)
        self.max_log_size = max_log_size
        self.lock = threading.Lock()
        self.current_log_file = None
        self._initialize_log_file()
    
    def _initialize_log_file(self):
        timestamp = datetime.now().strftime('%Y%m%d')
        self.current_log_file = self.log_directory / f'app_{timestamp}.log'
    
    def _sanitize_log_message(self, message):
        if not isinstance(message, str):
            message = str(message)
        
        message = message.replace('\r\n', ' ').replace('\n', ' ').replace('\r', ' ')
        message = message.replace('\t', ' ')
        message = re.sub(r'[\x00-\x08\x0B-\x0C\x0E-\x1F\x7F-\x9F]', '', message)
        message = html.escape(message, quote=True)
        message = message[:4096]
        
        return message
    
    def _sanitize_field(self, field):
        if not isinstance(field, str):
            field = str(field)
        
        field = field.replace('\r\n', ' ').replace('\n', ' ').replace('\r', ' ')
        field = field.replace('\t', ' ')
        field = re.sub(r'[\x00-\x08\x0B-\x0C\x0E-\x1F\x7F-\x9F]', '', field)
        field = field[:256]
        
        return field
    
    def _rotate_log_if_needed(self):
        if self.current_log_file.exists() and self.current_log_file.stat().st_size >= self.max_log_size:
            timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
            rotated_file = self.log_directory / f'app_{timestamp}.log'
            counter = 1
            while rotated_file.exists():
                rotated_file = self.log_directory / f'app_{timestamp}_{counter}.log'
                counter += 1
            self.current_log_file = rotated_file
    
    def write_log(self, level, message, service_name='unknown', request_id='', user_id='', additional_data=None):
        with self.lock:
            self._rotate_log_if_needed()
            
            timestamp = datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S.%f')[:-3]
            level = self._sanitize_field(level.upper())
            service_name = self._sanitize_field(service_name)
            request_id = self._sanitize_field(request_id)
            user_id = self._sanitize_field(user_id)
            message = self._sanitize_log_message(message)
            
            log_parts = [
                f'timestamp="{timestamp}"',
                f'level="{level}"',
                f'service="{service_name}"'
            ]
            
            if request_id:
                log_parts.append(f'request_id="{request_id}"')
            
            if user_id:
                log_parts.append(f'user_id="{user_id}"')
            
            log_parts.append(f'message="{message}"')
            
            if additional_data and isinstance(additional_data, dict):
                for key, value in additional_data.items():
                    safe_key = self._sanitize_field(str(key))
                    safe_value = self._sanitize_field(str(value))
                    log_parts.append(f'{safe_key}="{safe_value}"')
            
            log_line = ' '.join(log_parts) + '\n'
            
            try:
                with open(self.current_log_file, 'a', encoding='utf-8') as f:
                    f.write(log_line)
                return True
            except Exception as e:
                print(f"Error writing to log file: {e}")
                return False


class LoggingRequestHandler(BaseHTTPRequestHandler):
    log_writer = None
    
    def log_message(self, format, *args):
        pass
    
    def _send_response(self, status_code, message):
        self.send_response(status_code)
        self.send_header('Content-Type', 'application/json')
        self.end_headers()
        response = json.dumps({'status': 'success' if status_code == 200 else 'error', 'message': message})
        self.wfile.write(response.encode('utf-8'))
    
    def do_POST(self):
        if self.path != '/log':
            self._send_response(404, 'Not found')
            return
        
        try:
            content_length = int(self.headers.get('Content-Length', 0))
            if content_length > 1024 * 1024:
                self._send_response(413, 'Payload too large')
                return
            
            body = self.rfile.read(content_length)
            data = json.loads(body.decode('utf-8'))
            
            level = data.get('level', 'INFO')
            message = data.get('message', '')
            service_name = data.get('service', 'unknown')
            request_id = data.get('request_id', '')
            user_id = data.get('user_id', '')
            additional_data = data.get('data', {})
            
            if not message:
                self._send_response(400, 'Message is required')
                return
            
            success = self.log_writer.write_log(
                level=level,
                message=message,
                service_name=service_name,
                request_id=request_id,
                user_id=user_id,
                additional_data=additional_data
            )
            
            if success:
                self._send_response(200, 'Log written successfully')
            else:
                self._send_response(500, 'Failed to write log')
                
        except json.JSONDecodeError:
            self._send_response(400, 'Invalid JSON')
        except Exception as e:
            self._send_response(500, f'Internal server error')
    
    def do_GET(self):
        if self.path == '/health':
            self._send_response(200, 'OK')
        else:
            self._send_response(404, 'Not found')


def run_logging_server(host='0.0.0.0', port=8080, log_directory='logs'):
    log_writer = SecureLogWriter(log_directory=log_directory)
    LoggingRequestHandler.log_writer = log_writer
    
    server = HTTPServer((host, port), LoggingRequestHandler)
    print(f'Centralized logging server running on {host}:{port}')
    print(f'Logs will be written to: {Path(log_directory).absolute()}')
    
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        print('\nShutting down server...')
        server.shutdown()


if __name__ == '__main__':
    run_logging_server()